researcher_facing = [
  [ "R2", "Research Computing and Data and Researcher-Facing Support Awareness",
    [
      ['R2.7', 'Are researchers made aware of RCD use cases and how to access relevant <strong>RCD services and resources available to them via the institution</strong>? {Researchers Aware of RCD Resources}', '<p>Examples of this could include:</p><ul> <li>Researchers are provided with communications and/or other outreach about resources made specifically available to constituents via the institution (e.g., support, training, computing, data storage, library and data services, related centers or institutes), whether operated or procured by the institution, or via collaboration/resource-sharing by a partner institution.</li> </ul><p>A minimal Service Operating Level for this might include basic documentation, e.g., on a website or service catalog.</p><p>A basic Service Operating Level for this might further include an RCD staff role (or roles) that include responsibility to create awareness of RCD resources and services available on campus, as well as training and advice on tools and techniques.</p><p>A strong Service Operating Level for this might further include efforts to target materials to under-represented researcher communities (e.g., non-traditional users of computing and data tools beyond the typical physical sciences and engineering disciplines), and a practice of ensuring that documentation, training materials, etc. follow accessibility standards (e.g., WCAG).</p>', 'essential:True'],
      ['R2.8', 'Are researchers made aware of RCD use cases and how to access relevant <strong>RCD services and resources available externally</strong>?', '<p>Examples of this could include:</p><ul> <li>Researchers are provided with documentation, communications, and/or other outreach about available cross-institution, regional, national, and/or commercial resources not available specifically via the institution.</li> </ul><p>A minimal Service Operating Level for this might include basic documentation, e.g., on a website or service catalog.</p><p>A basic Service Operating Level for this might further include an RCD staff role (or roles) that include responsibility to create awareness of RCD resources and services available externally, as well as training and advice on tools and techniques.</p><p>A strong Service Operating Level for this might further include efforts to target materials to under-represented researcher communities (e.g., non-traditional users of computing and data tools beyond the typical physical sciences and engineering disciplines), and a practice of ensuring that documentation, training materials, etc. follow accessibility standards (e.g., WCAG).</p>', 'essential:True'],
      ['R2.1', 'Is there an institutional practice of <strong>proactive outreach to new or prospective faculty and research groups</strong> to raise awareness of RCD services and external resources? {Proactive Outreach as Practice}', '<p>Examples of this could include:</p><ul> <li>RCD staff contribute to discussions with prospective faculty or graduate students</li> <li>RCD staff have the skills and capacity to contribute to new graduate student orientations for computationally and data-intensive domains.</li> <li>RCD staff have the skills and capacity to conduct outreach to instructors who are teaching computationally and/or data-intensive methods.</li> </ul>', 'essential:False'],
      ['R2.3', 'Are researchers <strong>made aware of researcher-facing</strong> services and staff available via the institution?', '<p>For example, are researcher-facing services promoted as part of and beyond other RCD outreach and web-based resource listings, perhaps in materials distributed to prospective or new faculty and other researchers, or via other IT and campus communications, etc.</p>', 'essential:True'],
    ],
  ],
  [ "R1", "Research Computing and Data Implementation Support",
    [
      ['R1.3', 'Are researchers provided with <strong>individualized consultation for selecting and gaining access to the most appropriate RCD resources</strong> available via the institution or externally?', '<p>Examples of this could include:</p><ul> <li>Support guides for new and emerging technologies and techniques.</li> <li>RCD staff contribute to onboarding or orientation for new researchers and/or instructors who are teaching computationally and/or data-intensive methods.</li> </ul>', 'essential:False'],
      ['R1.6', 'Are researchers made aware of relevant <strong>externally-provided learning materials and opportunities</strong>, including training and events relevant to using specific RCD tools, services, and resources?', '<p>Learning resources might include user documentation, how-to guides, training videos, and training events for common RCD tools, programming languages, and external RCD resources (e.g., nationally-funded, commercial resources especially if via the institution, etc.), including multi-topic sources like The Carpentries. Awareness may be achieved via webpages listing ongoing learning resources and upcoming events, emails notifying researchers of these, and/or presentations to groups on campus highlighting such resources and events.</p>', 'essential:True'],
      ['R3.4', 'Are researchers provided with <strong>documentation and/or other self-service learning materials</strong> for using RCD services and resources available to them via the institution?', '<p>Examples may include written user documentation and how-to guides, training videos, and other self-service formats produced by the institution and promoted alongside the relevant institutionally-available resources.</p>', 'essential:False'],
      ['R1.1', 'Are researchers provided with <strong>training events and/or other synchronous learning opportunities</strong> for using RCD services and resources, whether available via the institution or externally?', '<p>Examples may include any institutionally-developed or procured synchronous training events, series, or for-credit courses teaching generalizable skills (e.g., paid or institutional-staffed Carpentries workshops) and/or the use of specific RCD tools or resources.</p>', 'essential:False'],
      ['R3.2', 'Are researchers provided with <strong>individualized consultation and responsive user support for optimizing and troubleshooting</strong> the use of specific RCD services and resources available via the institution?', '<p>For example, are researchers able to access individualized help via email, office hours, chat, and/or scheduled meetings for the use of locally-available RCD resources and services? Are these mechanisms accessible and known by researchers, and are they adequate for designing, optimizing, and troubleshooting end user workflows and practices on the relevant resource(s)?</p>', 'essential:False'],
      ['R4.1', 'Are researchers provided with individualized consultation for planning the integration of RCD services and resources <strong>across the research project lifecycle</strong>? {Full Research Lifecycle Support}', '<p>Examples of this could include:</p><ul> <li>Researchers are supported during proposal development, during the active award, and post funding.</li> <li>Researchers have access to support for project planning and proposal development.</li> <li>Researchers are supported in preparation of publications.</li> </ul>', 'essential:False'],
      ['R3.3', 'Do researcher-facing services include support for <strong>specialized and emerging use cases and technologies</strong>?', '<p>This includes support across different areas, including:</p><ul> <li>phases of AI/ML workflows (data preparation, model training, evaluation/tuning, deployment, monitoring)</li> <li>newer GPU systems and FPGAs</li> <li>quantum computing</li> </ul>', 'essential:False'],
    ],
  ],
  [ "R5", "Researcher-Facing Processes and Continuous Improvement",
    [
      ['R5.1', 'Do RCD staff leverage <strong>structured systems for executing and tracking researcher support conversations</strong>? {Ticketing System for User Support}', '<p>Examples might include:</p><ul> <li>The use of an email-based list or ticket-tracking system - or other systematic approach - for researcher-facing communication, issue tracking/resolution, and coordinating involvement among RCD teammates.</li> <li>Regular practices of reviewing open communication threads, leveraging internal note-taking and/or status indicators to inform and prioritize ongoing action.</li> <li>Periodic analysis of issues, response times, etc. to inform service management.</li>', 'essential:True'],
      ['R1.4', 'Do researcher-facing staff <strong>communicate user challenges and desires</strong> via RCD/IT leadership and governance, to inform the evolution of existing and potential new RCD services? {RF Staff Advocates to Leadership}', '<p>Examples of this might include:</p><ul> <li>RCD staff conduct periodic review of support requests to identify common problems, challenges, and/or gaps in services.</li> <li>RCD staff use common requests for help and/or training to improve, augment, or prioritize documentation and or training resources.</li> </ul>', 'essential:True'],
    ]
  ],
]
data_facing = [
  [ "D8", "Data Management, Discovery, and Creation",
    [
      ['D1.1', 'Do researchers have access to (and are they made aware of) <strong>consulting, documentation, and/or training for data lifecycle requirements, management, and planning</strong>? {Data Creation Resources}', "<p>For example, documentation, examples, consulting, and/or training for determining data lifecycle requirements and data management planning that applies data organization and access control approaches, naming and metadata conventions, solutions for reusability, etc. This is especially useful during the data creation stage.</p><ul> <li>A minimal Service Operating Level might include pointers to external documentation on data management approaches, tools, and funding agency details about requirements and Data Management Plans (DMPs).</li> <li>A basic Service Operating Level would add advising on the use of tools/platforms (e.g., Open Science Framework, electronic lab notebooks), on approaches and project-specific planning for managing a project's data, and on DMP development.</li> <li>A strong Service Operating Level would add training and/or campus-procured tools for Data Management, e.g., Lab Notebook software, Open Science Framework.</li> </ul>", 'essential:True'],
      ['D2.1', 'Do researchers have access to (and are they made aware of) <strong>consulting or other resources supporting data discovery</strong>? {Data Discovery Resources}', '<p>Examples might include:</p><ul> <li>Consulting, websites, hand-outs, or other resources to help identify appropriate data repositories (on campus, in domains, and more generally). Note: this may come from Research Computing and Data staff, library staff, or other partners.</li> <li>Some form of data inventory of datasets currently licensed or otherwise available to campus researchers.</li> </ul>', 'essential:True'],
      ['D2.2', 'Do researchers have access to (and are they made aware of) <strong>consulting on responsible data use</strong> based upon any <strong>terms-of-service / data-use agreements</strong>? {Data Crawling Expertise}', '<p>Examples of this can include:</p><ul> <li>Are there any library or other staff with knowledge about common Terms of Service for frequently crawled websites/data repositories and <strong>best practices guidance</strong>?</li> <li>Are there library or other staff with skills and capacity to <strong>inform policies and educate researchers on data use agreements</strong> (DUAs)?</li> </ul>', 'essential:False'],
      ['D2.3', 'Do researchers have access to (and are they made aware of) <strong>software supporting data collection</strong>? {Data Collection Software Tools}', '<p>Examples might include:</p><ul> <li>open source packages and other software for data crawling, web scraping, and other data gathering.</li> </ul><p>A minimal Service Operating Level for this might include basic documentation on the topic, with pointers to existing software packages.</p><p>A basic Service Operating Level for this might include advising from RCD staff on the selection and use of such tools, and documented pointers to external training and documentation resources.</p><p>A strong Service Operating Level for this might include institutionally-offered training on the selection and use of data collection tools, and/or staff who can provide hands-on assistance with the creation of data collection scripts and workflows.</p>', 'essential:False'],
    ],
  ],
  [ "D3", "Data Analysis",
    [
      ['D3.1', 'Do researchers have access to (and are they made aware of) <strong>consulting and/or learning resources on data wrangling/manipulation and analysis</strong>? {Data Analysis Consulting}', '<p>Examples might include:</p><ul> <li>Guidance on cleaning, transforming, integrating, validating, and documenting research data.</li> <li>Training and consultations on data analysis methods and best practices.</li> <li>Access to software and computing resources that support data preparation, analysis, visualization, and reproducible research.</li> <li>Assistance selecting appropriate tools, methods, and workflows for research projects.</li> <li>Support for reproducible and scalable approaches to data analysis.</li> </ul><p>A minimal Service Operating Level for this might include basic software and self-service documentation covering common data preparation and analysis tasks</p><p>A basic Service Operating Level for this might include institutional supported software, training, and consultation services that support routine data wrangling and analysis activities. Strong Service Operating Level</p><p>A strong Service Operating Level for this might include both advanced software resources and staff expertise capable of providing project-specific guidance on data preparation, analysis, reproducibility, workflow optimization, and scaling analytical approaches to meet research needs.</p>', 'essential:True'],
      ['D3.2', 'Do researchers have access to (and are they made aware of) <strong>software that supports data wrangling/manipulation and analysis</strong>? {Data Analysis Tools}', '<p>Examples might include:</p><ul> <li>Spreadsheet and tabular data tools.</li> <li>Platforms for data cleaning, transformation, and integration.</li> <li>Statistical analysis, machine learning, and visualization software.</li> <li>Interactive computing environments and research computing platforms that support data analysis workflows.</li> </ul><p>A minimal Service Operating Level for this might include general-purpose software suitable for basic data preparation and analysis.</p><p>A basic Service Operating Level for this might include a range of institutionally supported software and platforms designed for data cleaning, transformation, statistical analysis, visualization, and related research activities.</p><p>A strong Service Operating Level for this might include a well-supported ecosystem of software, platforms, and computing resources capable of supporting data-intensive and advanced analytical workflows across a broad range of research disciplines, with support for datasets and workflows that exceed the capabilities generally available to individuals on a workstation or personal storage subscription.</p>', 'essential:True'],
    ],
  ],
  [ "D4", "Data Visualization",
    [
      ['D4.1', 'Do researchers have access to (and are they made aware of) <strong>consulting and/or other learning resources on data visualization</strong>? {Resources for data visualization}', '<p>A minimal Service Operating Level for this might include basic documentation on the topic.</p><p>A basic Service Operating Level for this might include training and advice from RCD staff.</p><p>A strong Service Operating Level for this might include staff with expertise who can assist in creating or refining data visualization projects.</p>', 'essential:False'],
      ['D4.2', 'Do researchers have access to (and are they made aware of) <strong>software that supports data visualization</strong>? {Data Visualization Tools}', '<p>Examples might include:</p><ul> <li>General-purpose tools for creating charts, graphs, and other visual representations of data.</li> <li>Interactive visualization platforms that support exploration and communication of research data.</li> <li>Software and environments for creating customized visualizations, dashboards, and interactive data products.</li> <li>Visualization tools and workflows that support large, complex, multidimensional, or discipline-specific datasets.</li> </ul><p>A minimal Service Operating Level for this might include access to general-purpose software suitable for creating basic charts, graphs, and visual representations of research data.</p><p>A basic Service Operating Level for this might include a range of institutionally supported visualization tools and platforms that enable researchers to create, customize, and share visual representations of their data.</p><p>A strong Service Operating Level for this might include a well-supported ecosystem of visualization software, platforms, and expertise capable of supporting advanced visualization workflows across a broad range of research disciplines, including interactive, large-scale, specialized, or custom visualization needs that exceed the capabilities generally available to individuals using general-purpose desktop tools.</p>', 'essential:False'],
    ],
  ],
  [ "D5", "Research Data Curation, Storage, Backup, and Transfer",
    [
      ['D5.1', 'Do researchers have access to (and are they made aware of) <strong>consulting and/or learning resources</strong> to help them identify appropriate data repositories (on campus, in domains, and more generally) to place their data?', '<p>Examples of such repositories include generalist repositories such as Figshare, Zenodo, Dryad, and Open Science Framework (OSF), as well as domain-specific ones like GEO (Gene Expression Omnibus) for biology, NCBI Sequence Read Archive (SRA), RCSB Protein Data Bank (PDB), and dbGaP, and/or institutional repositories, as well as collaborative data grids such as OSN, iRODS, etc.</p><p>Examples of such services might include:</p><ul> <li>Support for identifying data to be preserved, archived, or discarded, and with the consideration of generalist repositories (e.g., Figshare, Zenodo, Dryad, and Open Science Framework), domain-specific options (e.g., Gene Expression Omnibus, NCBI Sequence Read Archive, RCSB Protein Data Bank (PDB), and dbGaP), and/or institutional repositories.</li> </ul><p>A minimal Service Operating Level might include self-service documentation, training materials, and information on available resources.</p><p>A basic Service Operating Level might include expertise and assistance in identifying resources and depositing data.</p><p>A strong Service Operating Level might include access and support for the physical and/or cyber resources and facilities (including those supplied by third parties) that will provide data storage, archival, and/or preservation beyond the term of grant funding.</p>', 'essential:True'],
      ['D5.2', 'Do researchers have access to (and are they made aware of) resources (e.g., staff) who can advise and assist with <strong>database creation and data organization</strong>? {Database Advice and Assistance}', '', 'essential:False'],
      ['D5.3', 'Do researchers have access to (and are they made aware of) <strong>tools/software</strong> that support <strong>data backup, storage, and integrity checking</strong>? {Data Management Tools}', '<p>A minimal Service Operating Level for this might include iCloud or Windows Backup for workstations.</p><p>A basic Service Operating Level for this might include backing up workstations and servers, possibly using tools such as Veeam, Rubrik, Naviki, Cohesity, or others.</p><p>A strong Service Operating Level for this might include staff with expertise who support the development or integration of tools/software that support data backup, storage, and integrity checking for research workflows.</p>', 'essential:True'],
      ['D5.6', 'Do researchers have access to (and are they made aware of) <strong>consulting and/or learning resources on metadata design and use</strong>, including good practices for use of identifiers? {Support for Metadata Design &amp; Use}', '<p>Example areas of available consulting, websites, hand-outs, or other resources could include:</p><ul> <li>Establishing controlled vocabularies for metadata and metadata fields for repository systems.</li> <li>Help with designing metadata applicable to their research.</li> <li>Assistance in setting up metadata for reusable data sets, physical samples, and research software.</li> <li>Guidance on recommended use or researcher identifiers; e.g., ORCiD (https://orcid.org/), ResearcherID (https://www.researcherid.com/), Scopus Author ID, etc.</li> <li>Training/learning resources on the above topics.</li> </ul><p>A higher Service Operating Level for this might include support such as:</p><ul> <li>Researcher identifiers are supported in the enterprise directory.</li> <li>Researchers have access to mechanisms/services to establish unique digital identifiers (DOIs) for data.</li> </ul>', 'essential:False'],
    ],
  ],
  [ "D6", "Research Data Policy Compliance",
    [
      ['D6.1', 'Does your institution have <strong>research data governance processes</strong> in place to establish and enforce data policies? {Data Governance and Policies}', '<p>A minimal Service Operating Level might include defining data governance strategy and objectives, roles and responsibilities, and policies and procedures.</p><p>A basic Service Operating Level might also include data quality management, security and privacy infrastructure and practices, and data governance communication and training.</p><p>A strong Service Operating Level might also include data governance measurement and monitoring, as well as a practice of continuous improvement.</p>', 'essential:False'],
      ['D6.2', 'Do researchers have access to (and are they made aware of) <strong>information and training on research data policy</strong>? {Training On Data Policy}', '<p>Example areas of information and training could include:</p><ul> <li>Processes to support and inform users on policy compliance, e.g., integrating security and compliance planning into data management plans (DMPs) and the broader research lifecycle.</li> <li>Training on research data security protocols.</li> <li>Advice on research computing and data compliance, security, management, and governance.</li> </ul><p>Note that this support should be independent of whether services are provided on-site or externally.</p>', 'essential:False'],
      ['D6.3', 'Do researchers have access to (and are they made aware of) support for <strong>analysis of research data sensitivity</strong>? {Support for Data Sensitivity Analysis}', "<p>This may include:</p><ul> <li>Cybersecurity education and training tailored to researchers, including faculty, staff, and students, e.g., as workshops, onboarding resources, checklists, and/or plain-language explanations of data protection responsibilities.</li> <li>Data Management Plan (DMP) compliance services (institutional framework, etc.).</li> <li>Data Use Agreement (DUA) review/analysis and consulting.</li> <li>Consulting, expertise, or other resources on contracts and government-mandated data controls (e.g., FISMA, CUI, NIST 800-171, FEDRAMP, HIPAA, NAGPRA/Indigenous data rights).</li> <li>Institutional Review Board (IRB) templates for datasets (with human or animal subjects), from small datasets that don't need HPC, up to large datasets that need HPC or Cloud services.</li> <li>Support at the nexus of the IRB, legal counsel, and an office of sponsored programs.</li> </ul><p>Note that this support should be independent of whether associated infrastructure services are provided on-site or externally.</p><p>A minimal Service Operating Level for this might include documentation, policies, training, checklists, or self-assessment resources that help identify data sensitivity and applicable requirements.</p><p>A basic Service Operating Level for this might include consultations or advisory services that help interpret data protection requirements and identify appropriate controls and institutional resources.</p><p>A strong Service Operating Level for this might include specialized expertise and formal review processes that evaluate data sensitivity, compliance obligations, security requirements, and appropriate handling procedures, with coordinated support across relevant institutional offices.</p>", 'essential:False'],
    ],
  ],
  [ "D7", "Research Data Security/Sensitive Data Support",
    [
      ['D7.1', 'Do researchers have access to (and are they made aware of) <strong>computing and data environments to manage and use moderately sensitive data</strong>, such as those requiring NIST 800-171 controls? {Support for Moderately Sensitive Data}', '<p>Examples might include:</p><ul> <li>Secure computing environments for storing, accessing, and analyzing controlled-access research data.</li> <li>Managed storage, compute, and data transfer services with appropriate security controls.</li> <li>Identity and access management capabilities supporting controlled access.</li> <li>Monitoring, auditing, incident response, and user training appropriate to protected research environments.</li> <li>Environments that support research workflows ranging from individual workstations to shared computing and large-scale computing resources.</li> </ul><p>A minimal Service Operating Level for this might include researchers having access to documented institutional options for storing and accessing moderately sensitive research data using approved security controls.</p><p>A basic Service Operating Level for this might include researchers having access to institutionally managed computing and storage environments that implement required controls for common categories of moderately sensitive research data.</p><p>A strong Service Operating Level for this might include researchers having access to scalable, well-supported secure research environments with documented compliance capabilities, operational support, monitoring, and consulting to support a broad range of protected research workloads.</p>', 'essential:False'],
      ['D7.2', 'Do researchers have access to (and are they made aware of) <strong>computing and data environments to manage and use "notice triggering" data</strong> (e.g., PHI, HIPAA, export-controlled, or licensed data)? {Support for Notice Triggering Data}', '<p>Examples of support might include:</p><ul> <li>Guidance on accessing, using, and maintaining secure or compliant research enclaves.</li> <li>Computing, storage, and data movement systems and tools.</li> <li>Brokering access to or providing tools, systems, and environments for secure computing environments aligned with regulatory requirements</li> <li>Data security protocols are in use and monitored.</li> </ul><p>A higher Service Operating Level might include tools, systems, and environments that scale from small to large data sets (i.e., up to high performance computing).</p>', 'essential:False'],
      ['D7.3', 'Do researchers have access to (and are they made aware of) <strong>computing and data environments to manage and use extremely sensitive data</strong>? {Support for Extremely Sensitive Data}', '<p>For example, data requiring cold room/air-gapped storage and computing, closely monitored access, dedicated data stewardship, etc.</p>', 'essential:False'],
    ]
  ],
]
software_facing = [
  [ "SW1", "Software Package Management",
    [
      ['SW1.1', 'Do researchers have access to (and are they made aware of) support, facilitation, and/or training for research <strong>software package compilation and installation</strong>? {Software Package Installation Support}', '<p>Examples of support could include:</p><ul> <li>An inventory of available modules and software packages available to researchers in shared computing environments (e.g., in HPC clusters, etc.).</li> <li>Researchers have access to locally-provisioned training, documentation, and/or support for standard software packages, middleware, libraries, and modules on RCD systems.</li> <li>Documentation and training on how to install and deploy Anaconda distributions, GATK, BLAST, etc., in VM and/or research workstation environments.</li> <li>RCD staff can support the compilation and installation of additional modules.</li> <li>Guidance and support for software citation, licensing, and repository deposition (e.g., Zenodo integration, SPDX licensing).</li> </ul><p>A minimal Service Operating Level for this might include documentation and/or tutorials.</p><p>At a higher Service Operating Level, there may be RCD staff who can support the compilation and installation of additional modules (e.g., in HPC clusters, etc.), and/or packages in VM and/or research workstation environments.</p>', 'essential:True'],
      ['SW1.3', 'Do researchers have access to (and are they made aware of) support for <strong>research software package assessment, documentation, and validation</strong>? {Software Assessment &amp; Validation}', '<p>Examples might include:</p><ul> <li>Guidance on evaluating software security, licensing, sustainability, export-control implications, and compliance considerations.</li> <li>Assistance assessing software provenance, maintenance status, community support, and risk.</li> <li>Vulnerability assessment and security review of research software packages.</li> <li>Documentation of software suitability for specific research environments or compliance requirements.</li> <li>Coordination among research computing, information security, procurement, compliance, and legal offices when needed.</li> </ul><p>A minimal Service Operating Level for this might include researchers having access to documentation, guidelines, or checklists that help evaluate software suitability, security, licensing, and compliance considerations.</p><p>A basic Service Operating Level for this might include researchers having access to consultation services that provide guidance on software selection, risk assessment, licensing, sustainability, and security considerations.</p><p>A strong Service Operating Level for this might include researchers having access to staff with expertise who can perform or coordinate formal software assessments, security reviews, vulnerability analyses, and compliance evaluations, and provide recommendations for deployment and use.</p>', 'essential:False'],
    ],
  ],
  [ "SW2", "Research Software Development",
    [
      ['SW2.1', 'Do researchers have access to (and are they made aware of) <strong>resources</strong> (e.g., staff) who can <strong>develop research software</strong>? {Research Software Development Staff}', '<p>For example, staff can be written into grants to architect or develop specific research applications or workflow components.</p>', 'essential:False'],
      ['SW2.2', 'Do researchers have access to (and are they made aware of) <strong>resources</strong> (e.g., staff) who can <strong>develop software for wide usage</strong>? {Website, Portal, etc. Support}', '<p>This may include software for websites, portals, and related applications.</p>', 'essential:False'],
      ['SW2.5', 'Do researchers have access to (and are they made aware of) consulting, expertise, or other resources to evaluate and improve software and/or website usability and accessibility? {Support for Accessibility Assessment}', '<p>Examples of support might include:</p><ul> <li>Documentation and training resources on usability and accessibility practices</li> <li>Access to and support for usability testing tools and/or services that can identify issues and suggest improvements.</li> <li>Access to and support for accessibility assessment tools that can identify issues and suggest improvements.</li> </ul><p>A minimal Service Operating Level for this might include basic documentation on the topic.</p><p>A basic Service Operating Level for this might include training and advice from staff skilled in these topics.</p><p>A strong Service Operating Level for this might include services to conduct usability and/or accessibility reviews, and provide suggested improvements or approaches to address issues.</p>', 'essential:False'],
    ],
  ],
  [ "SW3", "Research Software Optimization or Troubleshooting",
    [
      ['SW3.1', 'Do researchers have access to (and are they made aware of) <strong>performance optimizing tools and techniques</strong>? {Performance Optimization Tools}', '<p>Examples of this might include:</p><ul> <li>Performance and profiling tools such as Allinea/ARM Map, Intel VTune, etc.</li> <li>Monitoring tools such as Ganglia, NetData, DataDog, etc.</li> <li>Guidance on how to parallelize code, to port to GPUs or other new architectures, to analyze and improve efficiency, etc.</li> </ul><p>A minimal Service Operating Level for this might include basic documentation on the topic.</p><p>A basic Service Operating Level for this might include training and advice from RCD staff.</p><p>A strong Service Operating Level for this might include staff with expertise who can assist with performance optimizing tools and techniques (although this generally does not extend to deeper code porting or rewriting for new hardware, GPUs, etc.).</p>', 'essential:False'],
      ['SW3.3', 'Do researchers have access to (and are they made aware of) <strong>diagnostic and troubleshooting software</strong>? {Diagnostic &amp; Troubleshooting Tools}', '<p>Examples of this might include:</p><ul> <li>Tools such as Allinea DDT, Intel Inspector, etc.</li> <li>Monitoring tools for various computing environments.</li> </ul><p>A minimal Service Operating Level for this might include basic documentation on the topic.</p><p>A basic Service Operating Level for this might include training and advice from RCD staff on the use of these tools and techniques.</p><p>A strong Service Operating Level for this might include staff with expertise who can assist with diagnostics and troubleshooting (although this generally does not extend to deeper code review, debugging, etc.).</p>', 'essential:False'],
    ],
  ],
  [ "SW4", "Workflow Engineering",
    [
      ['SW4.1', 'Do researchers have access to (and are they made aware of) <strong>support for implementing research workflow packages</strong>? {Support for Research Workflow Tools}', '<p>For example, Toil, Pegasus, NextFlow, etc.</p>', 'essential:False'],
      ['SW4.2', 'Do researchers have access to (and are they made aware of) <strong>expertise and basic support to develop or script data workflows</strong>? {Data Workflow Scripting Support}', '<p>Examples of such support might include:</p><ul> <li>Guidance on selecting and using tools to automate research data processing, transformation, analysis, or movement.</li> <li>Assistance developing reproducible workflows for common research tasks such as data ingestion, cleaning, quality control, analysis, visualization, and publication.</li> <li>Consulting on workflow design, documentation, version control, automation, and reproducibility practices.</li> <li>Support for scripting and workflow orchestration across institutional, cloud, or external research computing resources.</li> <li>Training and examples that help researchers adapt established workflows to their own research projects.</li> </ul><p>A minimal Service Operating Level for this might include self-service documentation, training materials, and information on workflow best practices and available support resources.</p><p>A basic Service Operating Level for this might include consultations, office hours, workshops, training, and guidance on workflow design, scripting, automation, troubleshooting, and reproducible research practices.</p><p>A strong Service Operating Level for this might include staff with expertise who can help researchers develop, integrate, optimize, and scale reproducible research workflows using appropriate tools, services, and computing environments.</p>', 'essential:False'],
    ],
  ],
  [ "SW5", "Software Portability, Containers and Cloud Computing",
    [
      ['SW5.1', 'Do researchers have access to (and are they made aware of) <strong>support for making software portable</strong>? {Software Portability Support}', '<p>Examples of such support might include:</p><ul> <li>Good practices in the use of software repositories</li> <li>Tools, training, and support for containerization, e.g., Docker, Podman, and for HPC environments, Singularity</li> </ul>', 'essential:False'],
      ['SW5.3', 'Do researchers have access to (and are they made aware of) <strong>development support for commercial cloud architecture</strong>? {Cloud Solutions Development Staff}', '<p>Example use cases include: development of project-specific and domain-specific computing and data portals (like science gateways) or other multi-system workflow orchestration leveraging commercial cloud resources.</p><p>Such cloud platforms can include:</p><ul> <li>Local private campus cloud infrastructure</li> <li>National (e.g., XSEDE-supported) cloud infrastructure</li> <li>Commercial cloud platforms (e.g., AWS, Azure, GCP, etc.)</li> </ul><p>Guidance or training topics may include:</p><ul> <li>Platform (and vendor) evaluation and comparison</li> <li>Virtual machine management</li> <li>Cloud scaling</li> <li>Cloud architecture (and when appropriate, secure architecture)</li> <li>Orchestration design and development (Kubernetes, Puppet, Chef, etc.)</li> <li>Cloud budgeting and cost management</li> </ul><p>A minimal Service Operating Level for this might include documentation and/or tutorials.</p><p>A basic Service Operating Level for this might include training and/or consulting.</p><p>A strong Service Operating Level for this might include resources and capacity (e.g., staff) for architecting and deploying cloud solutions.</p>', 'essential:False'],
    ],
  ],
  [ "SW6", "Securing Access to Software",
    [
      ['SW6.1', 'Do researchers have access to (and are they made aware of) <strong>credential systems</strong> as an element of software security? {Credential Systems for Security}', '<p>For example, is there ready access to and support for integrating research software, research workflows, etc. with systems like CAS, Shibboleth, SAML, Single-Sign-on, etc.</p>', 'essential:False'],
      ['SW6.2', 'Do researchers have access to (and are they made aware of) <strong>support for utilizing licensed software</strong>? {Licensed Software Support}', '<p>For example, do researchers have <strong>access to licensed software</strong> that has been procured via institution? Are there <strong>license servers supporting such software</strong>, available via the institution?</p>', 'essential:True'],
      ['SW6.3', 'Do researchers have access to (and are they made aware of) support for <strong>managing export-controlled software</strong>? {Export Controlled Software Mgmnt}', '', 'essential:False'],
      ['SW6.4', 'Are processes defined and adhered to for <strong>educating, monitoring, and auditing</strong> Research Computing and Data staff, other IT professionals, and researchers, to <strong>comply with software license agreements</strong>? {License Compliance Processes}', '<p>A minimal Service Operating Level for this might include training on the terms and responsibilities of license agreements.</p><p>A basic Service Operating Level for this might include practices to maintain inventories of installed software and track installations.</p><p>A strong Service Operating Level for this might include the use of Software Asset Management tools to automate tracking and monitoring, as well as regular audits.</p>', 'essential:False'],
      ['SW6.5', 'Do researchers have access to (and are they made aware of) support for AI-assisted software development?**?', '<p>For example, are users provided with guidance and or consultative support for appropriate practices for AI-assisted software development via institutionally-provided tools and resources.</p>', 'essential:True'],
    ],
  ],
  [ "SW7", "Software Associated with Physical Specimens",
    [
      ['SW7.1', 'Do researchers have access to (and are they made aware of) <strong>software for managing physical collections</strong>? {Physical Collections Management Systems}', '', 'essential:False'],
      ['SW7.2', 'Do researchers have access to (and are they made aware of) <strong>software for discovery and research use of physical collections</strong>? {Physical Collections Discovery Tools}', '<p>A minimal Service Operating Level for this might include basic documentation on the topic.</p><p>A basic Service Operating Level for this might include training and advice from RCD staff on the software and best practices.</p><p>A strong Service Operating Level for this might include staff with expertise who can provide hands-on assistance in creating or refining software for the discovery and research use of physical collections.</p>', 'essential:False'],
    ]
  ],
]
systems_facing = [
  [ "SY1", "Infrastructure Support",
    [
      ['SY1.1', 'Does the institution have a professionally-managed and reliably functional datacenter(s) available for research computing and data resources? {Data Center Access/Availability}', '<p>For example, does the institution maintain one or more full-time IT operations and equipment facilities? Are there staff with time dedicated to managing datacenter infrastructure and following documented procedures, including appropriate access controls and auditing?</p><p>Counterexample: significant server infrastructure is operated in spaces shared with non-infrastructure equipment (a research laboratory, a grad student office space, "closet clusters"), with ad hoc management by non-dedicated staff.</p>', 'essential:True'],
      ['SY1.4', 'Are institutionally-available RCD resources operated and maintained via automated processes? {IT Infrastructure Automation Support}', '<p>For example, using Foreman, Razor, Puppet, Ansible, Chef, Kickstart, etc.</p><p>As a counterexample, infrastructure is managed with ad hoc scripts and ssh, and new systems are installed using unmodified OS installation media.</p>', 'essential:False'],
      ['SY1.5', 'Do systems-facing staff have the skills and capacity to apply container deployment and orchestration? {Container &amp; Orchestration Support}', '<p>For example, service-oriented architectures, Kubernetes or Docker for persistent services, Singularity for HPC application portability, etc.</p><p>As a counterexample, all programs are run directly on the host operating system and cannot be easily migrated to another host and/or operating system.</p>', 'essential:False'],
      ['SY9.2', 'Do RCD staff maintain documentation of various managed systems, including processes, procedures, and policies for infrastructure management? {RCD Infrastructure Mngmt. Processes}', '<p>Examples could include:</p><ul> <li>a comprehensive hardware and infrastructure inventory: Up-to-date lists of computing nodes, storage systems, DTNs, and network equipment, etc., including lifecycle and warranty status.</li> <li>system and network architecture diagrams: Clear documentation of cluster architecture, storage topology, research network design (e.g., Science DMZ layout, data transfer paths), etc.</li> <li>configuration and build documentation: Standard OS images, scheduler (e.g., Slurm) configurations, GPU/CUDA stacks, etc., including provisioning procedures.</li> </ul><p>A minimal Service Operating Level for this might be characterized as "the architecture is obvious if we look at what\'s in each rack", "the documentation is in my head or in emails spanning multiple years", or "all the relevant commands are in root\'s shell history".</p><p>A basic Service Operating Level for this might be characterized as having documentation from the original design or installation, but has since gone out of date. New systems-facing staff may quickly get the basic outline of the system, but find themselves adding missing documentation or working with existing staff on documentation updates.</p><p>A strong Service Operating Level for this might be characterized as closely aligning with principles of http://www.infrastructures.org/, https://web.archive.org/web/20250411044045/https://www.opsreportcard.com/, Limoncelli et al\'s <em>The Practice of System and Network Administration</em>, and similar references. The effort to onboard new systems-facing staff is minimized, and documentation is updated as changes occur.</p>', 'essential:False'],
      ['SY1.6', 'Does the institution manage identities and roles to support access to on-campus and external RCD resources? {Institutional IAM Support} {Role-Based System Access} {Federated IAM for External Collaborators}', '<p>Identities may be managed and federated using solutions such as Active Directory, Lightweight Directory Access Protocol (LDAP), InCommon federation, and others. Roles may be managed with dedicated identity management (IdM) software solutions, but role-based access is more about architecture and standard practices.</p><p>A minimal Service Operating level for this might only include accounts that are local to each resource or system, lack of multi-factor authentication (MFA), ad hoc access practices like "give this person access exactly matching this other person" or "give this person access to these specific folders".</p><p>A basic Service Operating Level for this might only integrate the local institution\'s central directory, partial support for MFA, and limited support for defining data access through common roles ("give everyone on this group or project identical access to their shared data, and manage who is included in the group or project") rather than individual identities.</p><p>A strong Service Operating Level for this would allow researchers\' external collaborators to use their home organization credentials (or other federated IDs) to access the institutions\' systems and data, ubiquitous and seamless MFA, consistent support for role-based access, and tools are provided to faculty and other designated project leads for managing access for institutional contributors (e.g., students and post-docs) and external collaborators.</p>', 'essential:False'],
    ],
  ],
  [ "SY2", "Computing Infrastructure",
    [
      ['SY2.1', 'Are high performance computing (HPC) systems and/or high throughput computing (HTC) available via the institution? {Support for HPC} {Support for HTC}', "<p>HPC: multiple computers connected to a high-speed, tightly coupled network, where software (similar to Slurm, PBS, or LSF) schedules dedicated access to shared resources to solve problems larger than an individual computer can handle. Applications and data are usually accessed from a central location, rather than distributed to local storage on each computer.</p><p>HTC: multiple computers connected over any network or the internet, where software (similar to HTCondor or Folding@home) distributes applications and data to solve large numbers of independent tasks (or small tasks, many times), each of which fits within the resources of a single computer.</p><p>A minimal Service Operating Level for this might include HPC or HTC operated ad-hoc by faculty and/or students on multi-purpose hardware, and made available to others associated with the institution.</p><p>A basic Service Operating Level for this might include some dedicated systems and staff for HPC and/or HTC systems.</p><p>A strong Service Operating Level for this might include fully-supported batch computing systems for HPC, HTC, high-memory, and GPU/AI computing use cases.</p><p>Note: a 'leading collaboration' status effectively equates to running systems for regional/multi-institutional sharing and/or national program (e.g., NSF and/or DOE-funded allocated resources).</p>", 'essential:True'],
      ['SY2.4', 'Are specialized computational hardware capabilities available via the institution? {Specialized Hardware Support}', "<p>Examples of this might include (depending upon the researchers' needs at an institution): Tensor Processing Units (TPUs), Field-Programmable Gate Arrays (FPGAs), Neural Processing Units (NPUs), Quantum hardware, etc. Traditional GPUs used for simulation or AI are excluded from this question, since they are often included in HPC and/or HTC systems.</p>", 'essential:False'],
      ['SY2.5', 'Are interactive computing services available via the institution? {Interactive Computing Support}', '<p>For example, support for virtual desktop infrastructure, notebooks (e.g., Jupyter), etc., whether via an external or commercial service or an internally managed option.</p>', 'essential:True'],
      ['SY2.6', 'Do resources available via the institution apply a standardized set of operating systems (e.g., for HPC, workstations, and virtual machines)? {Standardized Operating Systems}', '<p>For example: Are there consistent versions of Linux-based OS (e.g., Rocky, RHEL, or CentOS distribution on all HPC clusters), standard versions of Unix/macOS, or Windows on workstations?</p><p>The counterexample is that various HPC clusters run different OSs, and there are no standard OS distributions for VMs or workstations.</p><p>Considered from an organizational perspective, does the number of OSes supported reflect a considered flexibility for research needs, or is it a consequence of personal preference, local history, and/or a lack of organizational policy and practice?</p>', 'essential:False'],
    ],
  ],
  [ "SY3", "Storage Infrastructure",
    [
      ['SY3.2', "Is sufficient storage for working data available via the institution to support researchers' data-intensive computing needs? {Storage for Data Intensive Research}", '<p>Examples often include:</p><ul> <li>research-optimized and documented support via commercial cloud drives (e.g., OneDrive, Google Drive)</li> <li>active data storage services (a.k.a., "scratch" storage, often a parallel filesystem) sufficient for HTC/HPC.</li> <li>online or near-line storage for large datasets</li> <li>purpose-built S3 or other performant cloud storage</li> </ul><p>Counterexamples of this often include storing research data on:</p><ul> <li>individual researcher external drives or servers</li> <li>use of commercial drives via personal (non-institutional) accounts, e.g., OneDrive, Google Drive</li> </ul>', 'essential:False'],
      ['SY3.4', 'Are technologies available via the institution to facilitate data and access management? {Automated Data Management}', '<p>Examples may include:</p><ul> <li>data collection, management, and workflow platforms like iRODS, REDCap, Gen3, Globus Connect/Search, and others</li> <li>tools for automated tiering and data migration.</li> <li>tools for faculty to manage access by students and collaborators</li> </ul>', 'essential:False'],
    ],
  ],
  [ "SY4", "Network and Data Movement Infrastructure",
    [
      ['SY4.1', "Is the institution's network configured to support research demands from within the campus(es)? {High-Performance Research Network}", '<p>This is not about a given bandwidth or capacity number, but rather about researchers not being limited in their use of instruments, access to data, or workflows that require a needed scale of datasets to conduct their research.</p><p>Example measures could include:</p><ul> <li>The network is reliable (very little downtime) and accessible (e.g., wired and wireless connection capacity is sufficient for the needs of research and instruction).</li> <li>The network is performant for researchers\' needs (researchers can reasonably move data to and from the institution, among labs, etc.).</li> <li>The network architecture is well integrated with regional and national networks.</li> </ul><p>Note: this capability is about the network as a general service. More specific capabilities for data-intensive research are described in SY4.2.</p><p>A minimal Service Operating Level for this might include frequent network outages, multiple bottlenecks in network capacity, and predominantly using external physical media and "sneakernet" to transfer research data due to bandwidth constraints.</p><p>A basic Service Operating Level for this might include fewer network outages and a dedicated Science DMZ.</p><p>A strong Service Operating Level for this might include minimal network outages and ample bandwidth for the vast majority of researchers\' needs.</p>', 'essential:True'],
      ['SY4.3', 'Is infrastructure provided via the institution for secure, performant data movement? {Big Data Movement Tools}', '<p>Examples of this could include:</p><ul> <li>a protected subnet or campus/regional Science DMZ (segmenting applicable research data sources and patterns to bypass campus firewalls).</li> <li>virtualized networking techniques such as overlays, etc.</li> <li>dedicated data transfer nodes (DTN)</li> <li>data movement software; this may include Globus Connect, FDT, or BBCP, among others</li> <li>infrastructure for data buffering between high I/O lab instruments and the data center, and/or external resources, including special science instruments like cryogenic electron microscopes (cryo-EM), DNA sequencers, telescopes, etc. (common approaches to this are often referred to as "data capacitors" or "burst buffers").</li> </ul><p>A minimal Service Operating Level for this might include a one-size-fits-all network architecture, and predominantly using external physical media and "sneakernet" to transfer research data due to blocked network ports or other security limitations.</p><p>A basic Service Operating Level for this might include a dedicated Science DMZ largely defined by physical proximity to the data center, and some basic data movement software.</p><p>A strong Service Operating Level for this might include a flexible or software-defined network architecture and facilities for secure, performant data movement among researcher client systems, high I/O lab instruments, the data center, and external resources.</p>', 'essential:False'],
    ],
  ],
  [ "SY5", "Specialized Infrastructure",
    [
      ['SY5.1', 'Does the institution provide infrastructure support for edge computing and data devices, and/or Internet of Things (IoT) devices? {Edge Computing Support} {Sensor &amp; IOT Support}', '<p>Edge computing is a distributed computing model that places computation and storage closer to data-collection points and/or instruments. Applications often include specialized scientific instruments such as cryogenic electron microscopes (cryo-EM), DNA sequencers, telescopes, field research, etc.</p><p>Examples of infrastructure support may include:</p><ul> <li>computing and/or data capacity at the site of instruments and field devices</li> <li>wireless communications for field devices such as Cellular, Short-Range Wireless, and LPWAN</li> <li>IoT gateways including: Cellular Routers, LoRaWAN Gateways, Edge Computing Gateways, and/or Industrial Gateways</li> <li>IoT Controllers and cybersecurity support</li> </ul>', 'essential:False'],
      ['SY5.3', 'Does the institution provide infratructure support for personal computers beyond normal academic/administrative use? {Researcher Workstations Support}', '<p>Here, "personal computers" refers to laptops, desktops, workstations, or similar devices.</p><p>Examples of infrastructure support could include:</p><ul> <li>support for the physical hardware</li> <li>infrastructure to automate the installation and updates of operating systems and common applications</li> <li>flexible policies and procedures to accommodate the needs of research beyond what is generally supported (or allowed) for academic/administrative needs</li> </ul><p>Counterexample: support for basic Windows laptop with only academic/administrative applications from a limited catalog, where users don\'t have any administrative access, so don\'t mess with it.</p>', 'essential:True'],
      ['SY5.5', 'Are specialized experimental infrastructure environments available via the institution? {Specialized Computing Support}', '<p>Examples may include bare metal hardware, reconfigurable BIOS, OS, and network, or experimental cloud testbeds. Applications may come from fields like network, systems, and computer engineering, cybersecurity, and other applied computer-related sciences.</p>', 'essential:False'],
    ],
  ],
  [ "SY7", "Monitoring and Measurement",
    [
      ['SY7.1', 'Is RCD infrastructure monitored for utilization and performance? {Research Infrastructure Monitoring}', '<p>Examples of metrics might include:</p><ul> <li>usage metrics of multi-user computing and data systems (e.g., numbers, sizes, and durations of compute or data tasks, files, access patterns, transfers, etc.)</li> <li>device inventory across lab instruments and attached computing and storage devices</li> <li>traffic and performance monitoring of the research-supporting network, DMZ, DTN, etc., leveraging tools such as perfSONAR and/or a workflow environment to support end-to-end network performance troubleshooting</li> <li>measuring/monitoring the energy efficiency and environmental impact of research-computing infrastructure (e.g., PUE monitoring, carbon-aware job scheduling)</li> </ul><p>A minimal Service Operating Level for this might only include on-device monitoring.</p><p>A basic Service Operating Level for this might include data visualization tools and/or monitoring dashboards.</p><p>A strong Service Operating Level for this might include tools to detect and report problems or anomalies, predictive analytics to prevent outages, downtime, or security issues, and the practice of using data for operational decision-making.</p>', 'essential:False'],
      ['SY7.7', 'Does the institution track and report resource usage at the researcher/project level? {Tracking of Researcher/Project Usage}', '<p>For example, for institutional and funding agency reporting purposes. Counterexample, resource usage is only aggregated at the individual user level, and users are not easily grouped by PI or project.</p>', 'essential:False'],
    ],
  ],
  [ "SY11", "Best security practices for general-use environments",
    [
      ['SY11.1', 'Is Research Computing and Data (RCD) security coordinated with institutional IT Security and Compliance? {Coordination w/ Institutional IT Security}', '<p>For example:</p><ul> <li>Is the institutional IT security team leveraged for training and education?</li> <li>Do RCD staff leverage institutional compliance resources/offices?</li> </ul>', 'essential:True'],
      ['SY8.4', 'Is there a documented process for managing and auditing privileged (administrator) accounts, and do Research Computing and Data staff follow the associated procedures? {Privileged Account Management Procedures}', '<p>Example measures include documented policies and procedures for roles that should have privileged accounts, as well as tracking and periodic review of those accounts.</p><p>A counterexample might be the ad hoc granting of elevated privileges.</p>', 'essential:True'],
      ['SY11.2', 'Are Security Best practices implemented, including a security incident response plan?', '<p>Example practices could include:</p><ul> <li>security zones defined for different data sets and science workflows</li> <li>security monitoring for intrusion detection, malware, and other threats</li> <li>other recommendations from NIST, trusted CI, CVE, and others</li> </ul><p>A minimal Service Operating Level might be characterized as having documented practices and a security incident response plan, and that these procedures are followed when incidents arise.</p><p>A basic Service Operating Level might be characterized as also including review of plans and team membership on a regular basis (e.g., annually).</p><p>A strong Service Operating Level might be characterized as further including:</p><ul> <li>documented system security plans (SSPs) and plans of action and milestones (POAMs) defined for research computing and data environments</li> <li>completion of security assessments and/or accreditation (e.g., CMMC)</li> </ul>', 'essential:False'],
    ]
  ],
]
strategy_policy_facing = [
  [ "SP1", "Institutional Alignment",
    [
      ['SP1.1', 'Does the Research Computing and Data (RCD) team/group have a <strong>strategic plan</strong>, and is this strategic plan <strong>updated on a regular basis</strong>? {RCD Strategic Planning} {RCD Strategic Plan Aligned to Campus} {Support Resources Vision &amp; Strategy}', '<p>Examples of this could include:</p><ul> <li>There is a strategic plan and it is reviewed on a regular basis.</li> <li>The team has a clear vision, effective guidance, and strategy for the allocation and prioritization of support resources/personnel.</li> </ul><p>A minimal Service Operating Level might be characterized as having a strategic plan that is no more than 3 years old.</p><p>A basic Service Operating Level might be characterized as having a strategic plan that is reviewed on a yearly or every-other-year basis, and reflects institutional (campus-wide) strategic plans for IT, for research, and for the institution broadly.</p><p>A strong Service Operating Level might be characterized as having a strategic planning process and practice for IT, for research, and for the institution broadly that recognizes RCD strategic goals, and in which the RCD strategic plan has clear connections to the broader institutional strategic plans.</p>', 'essential:True'],
      ['SP1.3', 'Do the Research Computing and Data (RCD) service and support community and underlying IT service providers have a good <strong>awareness and understanding of major research efforts/initiatives across the institution</strong>? {Awareness of Institutional Research Goals}', '<p>This awareness might come through regular briefings to RCD and IT leadership and/or engagement with research leadership. A counter example for lack of awareness and understanding is: are RCD and/or IT leadership often surprised by the needs of new grants or research initiatives?</p>', 'essential:False'],
      ['SP1.4', '<strong>Are campus leaders and relevant governance groups aware</strong> of Research Computing and Data (RCD) strategic priorities? {Inst. Leaders Aware of RCD Priorities}', "<p>Examples or evidence of such understanding may include:</p><ul> <li>The institution's research priorities are well-understood by campus leadership.</li> <li>RCD strategic priorities understood and supported by campus leadership.</li> <li>Campus leadership understand and support the need for staff capacity to focus on outreach, training, and other support to researchers in the use of RCD services (whether on campus, from national resources, commercial services, etc.)?</li> </ul>", 'essential:False'],
      ['SP1.7', 'Are Research Computing and Data (RCD) <strong>resources and services available in support of instruction</strong> or other pedagogical uses? {RCD Support for Instruction}', '<p>For example:</p><ul> <li>Can and do instructors leverage RCD resources for instruction?</li> <li>Are instructors effectively informed about available resources?</li> </ul>', 'essential:True'],
      ['SP1.8', 'Is there <strong>a governance body (e.g., faculty advisory group)</strong> that reviews and advises on priorities for campus-level investments for Research Computing and Data (RCD) infrastructure? {Faculty Advisory Group Engagement}', '<p>This is generally a dedicated group for RCD, although it may be part of a larger research or IT advisory body, but examples of this might include:</p><ul> <li>A designated group of faculty, research, and/or IT representatives that meets regularly (e.g., quarterly or once a semester) to review and advise on topics such as emerging needs, new technologies, and/or campus funding to sustain or supplement RCD programs.</li> <li>A committee within the overall faculty governance body; at a smaller campus, this may be a general IT committee, but that is prepared to advise and recommend funding on RCD-specific capabilities.</li> <li>A set of one or more committees that each advise on different RCD aspects or units, e.g., scalable data storage services, the research computing unit, software procurement policy, etc. (perhaps at a larger campus with a deeper portfolio and/or multiple collaborative RCD providers).</li> </ul>', 'essential:True'],
    ],
  ],
  [ "SP3", "Funding",
    [
      ['SP3.1', 'Are Research Computing and Data (RCD) <strong>services funded in a sustainable manner</strong>? {Sustainable Funding for RCD Services}', '<p>Some examples or evidence of this might include:</p><ul> <li>There is recurring program budget for the RCD staff and services operations (i.e., these are not primarily dependent upon grants or other non-recurring funding).</li> <li>Campus funding partnerships are formalized with an MOU or equivalent agreement.</li> <li>For activities funded from contracts and grants, there is a strong track-record of renewed funding.</li> </ul>', 'essential:True'],
      ['SP3.2', 'Are <strong>new funding opportunities proactively identified and assessed</strong> at an institutional level, for relevance to institutional mission and alignment to Research Computing and Data (RCD) needs and priorities? {New Funding Opportunities Identified}', '<p>Examples of this might include tracking calls from national funders for:</p><ul> <li>Major Research Instrumentation (MRI) grants (or equivalents) that could support new computing and/or data capacity in support of research initiatives</li> <li>Grants that support expanded research cyberinfrastructure</li> <li>Grants or other funding opportunities that support training or professional development of RCD staff</li> </ul><p>A minimal Service Operating Level could be characterized as ad hoc review of opportunities, while "Strong support, awareness, &amp; commitment" could be characterized as a structured process coordinated among RCD staff and other institutional stakeholders.</p>', 'essential:False'],
      ['SP3.3', "Do <strong>research funding activities actively integrate the campus's Research Computing and Data</strong> (RCD) provider(s)? {Research Funding Engaged with RCD}", '<p>For example:</p><ul> <li>Do RCD teams collaborate with the Contracts and Grants teams to be aware of grants with computational or data needs?</li> <li>Is there a means for Principal Investigators (PIs) to indicate that a proposed submission has significant or unusual computational, data, or other infrastructure aspects and/or needs?</li> <li>Do RCD staff assist Principal Investigators (PIs) with proposal preparation (e.g., on hardware specification)?</li> </ul>', 'essential:False'],
      ['SP3.4', 'Do Research Computing and Data (RCD) services teams <strong>submit</strong> (extramural) <strong>grant proposals</strong> for RCD investments and innovations? {RCD Teams Submit Grant Proposals}', '<p>A minimal Service Operating Level might be characterized as RCD staff occasionally being involved in grant preparation and being named as Senior Personnel.</p><p>A basic Service Operating Level might be characterized as RCD staff regularly being involved in grant preparation and occasionally acting as Principal or Co-Principal Investigators.</p><p>A strong Service Operating Level might be characterized as RCD staff regularly being involved in grant preparation as Principal or Co-Principal Investigators, and having been awarded such grants.</p>', 'essential:False'],
    ],
  ],
  [ "SP7", "Service Management, Processes, and Practices",
    [
      ['SY8.3', 'Do Research Computing and Data staff leverage a <strong>structured system for tracking internal work</strong>?', "<p>Structured systems might include the use of an internal ticketing systems and/or other project management platform within which issues, progress, and 'owners' are documented. These may be integrated/continuous with the system for receiving and handling user-facing issues, or may be separate.</p>", 'essential:False'],
      ['R2.4', 'Does the institution have a process to conduct <strong>regular assessment of Research Computing and Data (RCD) services and support</strong>, including user satisfaction and impact? {Assessment of RCD Outreach} {Recognized Value of RCD Facilitation}', '<p>Examples might include:</p><ul> <li>Periodic satisfaction surveys to assess researcher awareness, satisfaction, and engagement related to RCD services and support.</li> <li>Periodic data collection to assess the impact of RCD support. These often include data on publications, grants, etc. for active users, as well as faculty and graduate student recruitment and retention cases supported.</li> <li>Practices (conversation/email logging, surveys, interviews, etc.) to capture informal feedback and/or gather quotes from active research users, perhaps to communicate these to other stakeholders.</li> </ul><p>A minimal Service Operating Level might be characterized as occasional surveys, data collection, and testimony capture that is used by the RCD team and in communications with leadership, etc.</p><p>A basic Service Operating Level might be characterized as regular surveys or data collection that is reviewed by the RCD team, and shared with IT leadership, Office of Research, or other institutional leadership to inform budget requests and institutional planning</p><p>A strong Service Operating Level might be be characterized by assessment and impact reports resulting in institution-level leadership recognizing and valuing the impact of RCD services and support (including return/value on investment), and valuing RCD at the same level as or higher than other enterprise services when discussing the prioritization of campus (budget) resources.</p>', 'essential:False'],
      ['SY10.2', 'Do Research Computing and Data (RCD) staff follow a <strong>formal process for review, planning, and procurement of research computing, data, networking, etc. resources</strong>? {Resource Procurement Processes}', '<p>Examples of this might include:</p><ul> <li>Defining and maintaining a systems and infrastructure lifecycle plan.</li> <li>Documenting requirements, benchmarks, cost analysis, acceptance plans, terms and conditions, etc.</li> <li>Maintaining a business-continuity and disaster-recovery plan specifically for RCD services.</li> </ul>', 'essential:False'],
      ['SY10.1', 'Do Research Computing and Data (RCD) <strong>planning processes include/incorporate security and compliance</strong> considerations? {Planning for Security &amp; Compliance}', '<p>Examples of this might include:</p><ul> <li>RCD staff monitor and respond to changes in research cybersecurity policy and regulatory requirements.</li> <li>RCD staff engage with campus and national stakeholders to build awareness of likely (or at least possible) future changes in research cybersecurity policy and regulatory requirements.</li> </ul><p>A strong Service Operating Level might be characterized by proactive adaptation of templates, internal documentation, and guidance related to evolving federal expectations.</p>', 'essential:False'],
      ['SP7.5', 'Does the institution <strong>assess, support, and regularly update research cybersecurity risks, standards, and solutions</strong>?', '<p>Some examples of this could include:</p><ul> <li>There are legal and/or policy oversight practices and controls in place for AI/LLM related activity. These might be informed by a framework like the NIST Artificial Intelligence Risk Management Framework (AI RMF).</li> <li>Researchers have access to (and make use of) resources explaining data security levels/classes and the computing and data services appropriate for use with each level/class.</li> </ul>', 'essential:False'],
      ['SP7.6', 'Does the institution provide <strong>support, risk assessment, or compliance guidance for lab- or faculty-managed research infrastructure</strong> that is otherwise outside central IT management or governance?', '<p>Examples of this might include:</p><ul> <li>Consultation for securely integrating or mitigating risk on standalone servers, cloud-based systems, etc.</li> <li>Support and guidance on securing workstations that do not benefit from central management.</li> <li>Support and guidance on securing custom (locally developed) applications.</li> <li>Other general consultation and guidance services, like those relevant to meeting Cybersecurity Maturity Model Certification (CMMC) requirements.</li> </ul>', 'essential:False'],
      ['SY1.3', 'Are solutions in place via the institution that ease the use of commercial cloud services by researchers?', '<p>Are there institutional agreements (e.g., covering legal and compliance issues) and billing processes in place (e.g., that allow institutionally-coordinated charging to research grants)? Are technology integrations in place that allow researchers to access cloud resources using their institutional identity?</p><p>A counterexample might be that researchers are forced to use free credits or their own cloud accounts for their research.</p>', 'essential:False'],
    ],
  ],
  [ "SP4", "Partnerships and Engagement with External Communities",
    [
      ['SP4.1', 'Do Research Computing and Data (RCD) services teams <strong>actively engage with regional and/or national RCD peers/communities</strong>? {RCD Teams Engaged Regionally/Nationally}', '<p>Examples of this might include:</p><ul> <li>Meeting with or closely following communications from regional research network providers, NSF regional Big Data Hubs, etc.</li> <li>Attending presentations and/or participating in groups at CaRCC, the EDUCAUSE RCD CG, etc.</li> <li>Attending periodic meetings held by CASC, Internet2, Campus Champions, the EPSCoR CI community, MS-CC CI activities, etc.</li> </ul><p>A minimal Service Operating Level could be characterized as periodic attendance/engagement, while "Strong support, awareness, &amp; commitment" could be characterized as actively contributing to a working or interest group at CaRCC, CASC, EDUCAUSE RCD CG, etc.</p>', 'essential:True'],
      ['SP4.2', 'Are Research Computing and Data <strong>services operated or contributed by the institution for external users</strong>, via regional or national resource allocation and/or sharing programs, etc.? {External Access to RCD Services}', "<p>Examples of this might include:</p><ul> <li>Operating funded resources as part of a national allocation program like NSF ACCESS, NAIRR, etc.</li> <li>Operating funded resources as part of a regional consortium, e.g., RMACC, GPN, etc.</li> <li>Contributing resources to a regional or national consortium, e.g., the OSG's Open Science Pool.</li> </ul>", 'essential:False'],
      ['SP4.3', 'Does the institution actively engage in <strong>external partnerships</strong> for RCD funding and/or resource sharing, with other specific institutions, industry partners, etc.? {External Partnership Engagement}', '<p>Examples of this might include:</p><ul> <li>Resource-sharing among two or more institutions, not necessarily as a part of a formalized regional consortium or national program, but perhaps within the same university system.</li> <li>Active industry partnerships.</li> </ul>', 'essential:False'],
    ],
  ],
  [ "SP5", "Team and Professional Development of Research Computing and Data Staff",
    [
      ['SP5.2', 'Are Research Computing and Data (RCD) <strong>staff provided with opportunities for professional development and career advancement</strong>? {RCD Career Advancement Support}', '<p>An example of a minimal Service Operating Level might be that management and staff discuss career paths for each role.</p><p>An example of a basic Service Operating Level might be that each RCD staff member has a professional development plan and staff are encouraged/supported in pursuing career advancement opportunities including training, professional networking, authoring or co-authoring RCD publications, etc.</p><p>An example of a strong Service Operating Level might be that RCD staff have access to funding (and time allowed) for training, new skills development, etc.</p><p>Note that while some aspects of this (like a professional development plan) will generally be supported by a supervisor or mentor at the institution, some professional development opportunities may be provided outside the institution, e.g., by dedicated programs, or in regional or national communities.</p>', 'essential:True'],
      ['SY10.4', 'Are Research Computing and Data (RCD) staff engaged with exploring, testing, and deploying emerging or advanced tools, methodologies, and technologies needed or likely to be needed by researchers? {Engagement on Emerging Needs/Gaps}', '<p>Examples of this include:</p><ul> <li>Researcher-Facing staff have time allotted for exploring, training, and developing understanding of emerging or advanced tools and methodologies?</li> <li>Systems-Facing staff have time allotted for evaluating, testing, training and developing understanding of infrastructure needs for deploying emerging or advanced tools and technologies.</li> </ul><p>A basic Service Operating Level would include regular dedicated time for these activities, while "Strong support, awareness, &amp; commitment" might also include this as a part of professional development plans.</p>', 'essential:False'],
      ['SP5.3', 'Are Research Computing and Data (RCD) <strong>staff permitted to use staff time to engage in regional or national community efforts</strong>? {Staff Time for Professional Communities}', '<p>Examples of this include:</p><p>A minimal Service Operating Level might be characterized as RCD staff occasionally participating in (e.g., attending calls or presentations from) regional networks, Campus Champions work, Linux user groups, CaRCC, etc.</p><p>A basic Service Operating Level might be characterized as RCD staff regularly participating in such activities, and occasionally engaging or contributing to these activities.</p><p>A strong Service Operating Level might be characterized as RCD staff being contributing members of one or more working or interest groups at CaRCC, CASC, EDUCAUSE RCDCG, etc., and/or they contribute to community efforts like Carpentries training materials or activities.</p>', 'essential:False'],
      ['SP6.1', 'Is there a <strong>policy and practice</strong> to ensure (and if necessary, improve) <strong>community, accessibility, and belonging</strong>, on the Research Computing and Data (RCD) staff? {Inclusive Policies and Practices}', '<p>Examples might include:</p><ul> <li>RCD staff are regularly surveyed/polled/queried on engagement, cultural climate, etc.</li> <li>User-facing communication, applications, and services are evaluated for accessibility.</li> <li>RCD management tracks this over time, and results are used to develop ongoing strategies to improve community, accessibility, and belonging.</li> <li>Hiring practices include measures to expand applicant pools and reduce bias.</li> </ul>', 'essential:True'],
      ['SP6.3', 'Do Research Computing and Data (RCD) staff have <strong>access to training to support community, accessibility, and belonging</strong>? {Training for Inclusion}', '<p>Examples might include:</p><ul> <li>RCD staff have access to training on unconscious bias, different communication styles, multicultural awareness, etc.</li> <li>RCD staff have access to training on identifying and addressing accessibility issues associated with outreach and communications, applications, user-facing services, etc.</li> <li>RCD staff are supported with training, team principles, and practices that ensure a culture of belonging by minimizing discrimination and harassment.</li> </ul>', 'essential:False'],
    ]
  ],
]


